"""Generated by w2a — sequential_pipeline pattern for "PR Summary Generator"."""

from __future__ import annotations

from crewai import Agent, Crew, Process, Task

from config import build_llm
from tools import ALL_TOOLS

_llm = build_llm()

agent_diff_analyst = Agent(
    role='PR Analyst',
    goal='Determine the functional behavior change, identify risky areas, and verify test coverage in a PR.',
    backstory='As a precision-focused PR Analyst, you specialize in deep code analysis to improve review quality. Your expertise lies in distinguishing between substantive changes and trivial fixes to streamline the engineering lifecycle.',
    tools=ALL_TOOLS,
    llm=_llm,
    verbose=True,
)
agent_comment_generator = Agent(
    role='Technical Writer',
    goal='Synthesize PR findings into a clear, actionable comment for reviewers.',
    backstory='You are a seasoned Technical Writer dedicated to synthesizing complex technical findings into clear, actionable summaries. You transform the analytical output into professional pull requests comments that facilitate faster, more effective review cycles.',
    tools=ALL_TOOLS,
    llm=_llm,
    verbose=True,
)


task_analyze_pr = Task(
    description='Examine the pull request diff to classify it as trivial or substantive. Extract core behavior changes, identify potential risks such as migrations or auth config updates, and verify the presence of adequate test coverage to produce a technical assessment.\n\nActual PR diff to analyze:\n{input}',
    expected_output='A technical assessment indicating if the PR is trivial or substantive, including details on behavior changes, identified risks, and test coverage status.',
    agent=agent_diff_analyst,
)
task_write_pr_comment = Task(
    description='Using the technical assessment from the diff analyst, draft a structured PR comment. For trivial fixes, provide a concise one-liner, and for substantive changes, construct a comprehensive summary that highlights functional impacts and risk factors for reviewers.',
    expected_output="A PR comment containing either a concise one-liner or a structured summary of the PR's impact.",
    agent=agent_comment_generator,
    context=[task_analyze_pr],
)


def build_crew() -> Crew:
    return Crew(
        agents=[agent_diff_analyst, agent_comment_generator],
        tasks=[task_analyze_pr, task_write_pr_comment],
        process=Process.sequential,
        verbose=True,
    )
